#include <stdlib.h>
#include <stdio.h>

#include "../common.h"
#include "../util/timer/timer.h"

extern "C" void kernel_gpu_cuda_wrapper(record *records,
										long records_mem,
										knode *knodes,
										long knodes_elem,
										long knodes_mem,
										int order,
										long maxheight,
										int count,
										long *currKnode,
										long *offset,
										int *keys,
										record *ans);

__global__ void kernel_gpu_cuda(record *records,
							   knode *knodes,
							   long knodes_elem,
							   int order,
							   long maxheight,
							   int count,
							   long *currKnode,
							   long *offset,
							   int *keys,
							   record *ans)
{
	int bid = blockIdx.x;
	if (bid >= count) return;

	int threadsPerBlock = min(1024, order);

	for (int i = 0; i < maxheight; i++) {
		for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
			if (keys[bid] >= knodes[currKnode[bid]].keys[thid] && keys[bid] < knodes[currKnode[bid]].keys[thid + 1]) {
				if (knodes_elem > knodes[offset[bid]].indices[thid]) {
					offset[bid] = knodes[offset[bid]].indices[thid];
				}
			}
		}
		__syncthreads();
		currKnode[bid] = offset[bid];
	}

	for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
		if (keys[bid] == knodes[currKnode[bid]].keys[thid]) {
			ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
		}
	}
}

extern "C" void kernel_gpu_cuda_wrapper(record *records,
										long records_mem,
										knode *knodes,
										long knodes_elem,
										long knodes_mem,
										int order,
										long maxheight,
										int count,
										long *currKnode,
										long *offset,
										int *keys,
										record *ans)
{
	int threadsPerBlock = min(1024, order);
	kernel_gpu_cuda<<<count, threadsPerBlock>>>(records, knodes, knodes_elem, order, maxheight, count, currKnode, offset, keys, ans);
	cudaDeviceSynchronize();
}

void kernel_cpu(	int cores_arg,
					record *records,
					knode *knodes,
					long knodes_elem,
					int order,
					long maxheight,
					int count,
					long *currKnode,
					long *offset,
					int *keys,
					record *ans)
{
	long long time0;
	long long time1;
	long long time2;

	time0 = get_time();

	setdevice();

	time1 = get_time();

	long records_mem = ((long)knodes - (long)records);
	long knodes_mem = knodes_elem * sizeof(knode);

	kernel_gpu_cuda_wrapper(records, records_mem, knodes, knodes_elem, knodes_mem, order, maxheight, count, currKnode, offset, keys, ans);

	time2 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time2 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time2 - time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

