#include <stdlib.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_cpu_2.h"

extern "C" void kernel_gpu_cuda_wrapper_2(knode *knodes,
										  long knodes_elem,
										  long knodes_mem,
										  int order,
										  long maxheight,
										  int count,
										  long *currKnode,
										  long *offset,
										  long *lastKnode,
										  long *offset_2,
										  int *start,
										  int *end,
										  int *recstart,
										  int *reclength);

__global__ void kernel_gpu_cuda_2(knode *knodes,
								 long knodes_elem,
								 int order,
								 long maxheight,
								 int count,
								 long *currKnode,
								 long *offset,
								 long *lastKnode,
								 long *offset_2,
								 int *start,
								 int *end,
								 int *recstart,
								 int *reclength)
{
	int bid = blockIdx.x;
	if (bid >= count) return;

	int threadsPerBlock = min(1024, order);

	for (int i = 0; i < maxheight; i++) {
		for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
			if (start[bid] >= knodes[currKnode[bid]].keys[thid] && start[bid] < knodes[currKnode[bid]].keys[thid + 1]) {
				if (knodes_elem > knodes[currKnode[bid]].indices[thid]) {
					offset[bid] = knodes[currKnode[bid]].indices[thid];
				}
			}
			if (end[bid] >= knodes[lastKnode[bid]].keys[thid] && end[bid] < knodes[lastKnode[bid]].keys[thid + 1]) {
				if (knodes_elem > knodes[lastKnode[bid]].indices[thid]) {
					offset_2[bid] = knodes[lastKnode[bid]].indices[thid];
				}
			}
		}
		__syncthreads();
		currKnode[bid] = offset[bid];
		lastKnode[bid] = offset_2[bid];
	}

	for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
		if (start[bid] == knodes[currKnode[bid]].keys[thid]) {
			recstart[bid] = knodes[currKnode[bid]].indices[thid];
		}
	}

	for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
		if (end[bid] == knodes[lastKnode[bid]].keys[thid]) {
			reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
		}
	}
}

extern "C" void kernel_gpu_cuda_wrapper_2(knode *knodes,
										  long knodes_elem,
										  long knodes_mem,
										  int order,
										  long maxheight,
										  int count,
										  long *currKnode,
										  long *offset,
										  long *lastKnode,
										  long *offset_2,
										  int *start,
										  int *end,
										  int *recstart,
										  int *reclength)
{
	int threadsPerBlock = min(1024, order);
	kernel_gpu_cuda_2<<<count, threadsPerBlock>>>(knodes, knodes_elem, order, maxheight, count, currKnode, offset, lastKnode, offset_2, start, end, recstart, reclength);
	cudaDeviceSynchronize();
}

